package fidelity

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"slices"
	"strings"
)

// Fixture represents a single fidelity test fixture — the ground truth
// generated by running real vscode-textmate over a source sample.
type Fixture struct {
	VsctmVersion      string                  `json:"vsctmVersion"`
	Grammar           string                  `json:"grammar"`
	GrammarSourceHash string                  `json:"grammarSourceHash"`
	Source            string                  `json:"source"`
	Themes            map[string]ThemeFixture `json:"themes"`
}

// ThemeFixture holds the expected output for a single theme.
type ThemeFixture struct {
	Tokens [][]FixtureToken `json:"tokens"`
	HTML   string           `json:"html"`
}

// FixtureToken is a single token with resolved style, as produced by Shiki.
type FixtureToken struct {
	Start     int      `json:"start"`     // UTF-8 byte offset from line start
	End       int      `json:"end"`       // UTF-8 byte offset from line start
	Text      string   `json:"text"`      // token text content
	Scopes    []string `json:"scopes"`    // TextMate scope stack (outermost first)
	Color     string   `json:"color"`     // resolved foreground hex (e.g. "#D73A49")
	FontStyle int      `json:"fontStyle"` // bitmask: 1=italic, 2=bold, 4=underline, 8=strikethrough
}

// LoadFixture reads and unmarshals a single fixture JSON file.
func LoadFixture(path string) (*Fixture, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("fidelity: read fixture %s: %w", path, err)
	}
	var f Fixture
	if err := json.Unmarshal(data, &f); err != nil {
		return nil, fmt.Errorf("fidelity: parse fixture %s: %w", path, err)
	}
	return &f, nil
}

// LoadFixtures loads all *.json fixture files from a directory, sorted by name.
func LoadFixtures(dir string) ([]*Fixture, error) {
	entries, err := os.ReadDir(dir)
	if err != nil {
		return nil, fmt.Errorf("fidelity: read fixture dir %s: %w", dir, err)
	}

	var fixtures []*Fixture
	var names []string
	for _, e := range entries {
		if e.IsDir() || !strings.HasSuffix(e.Name(), ".json") {
			continue
		}
		names = append(names, e.Name())
	}
	slices.Sort(names)

	for _, name := range names {
		f, err := LoadFixture(filepath.Join(dir, name))
		if err != nil {
			return nil, err
		}
		fixtures = append(fixtures, f)
	}
	return fixtures, nil
}
